    \begin{description}
        \item【详解】因为 $A=\left\{x \mid x=\sin \frac{n \pi}{2}, n \in \mathbf{Z}\right\}$，所以 $A=\{-1,0,1\}$，$B=\{0,1\}$ 对A: $A \neq B$，故错误；对B: $B \subseteq A$，故正确；对C: $A \cap B=\{0,1\}$，故错误；对D: $C_{A}B=\{-1\}$，故错误；故选：B
    \end{description}
    \item 【答案】
    \begin{description}
        \item【详解】设正四棱台侧面的高为 $h$，则 $2^{2}+8^{2}+\frac{2+8}{2}\times h\times 4=148$，$h=4$，所以侧棱长为 $\sqrt{4^{2}+\left(\frac{8-2}{2}\right)^{2}}=5$。故选：C
    \end{description}
    \item 【答案】B
    \begin{description}
        \item【解析】因为 $\overline{BD}=\overline{BC}+\overline{CD}$，$5\overline{a}+4\overline{b}+\overline{a}$，$2\overline{b}=6\overline{a}$，$6\overline{b}$，且A，B，D三点共线，所以存在实数 $\lambda$，使得 $\overline{AB}=\lambda\overline{BD}$，即 $\overline{a}+m\overline{b}=\lambda\left(6\overline{a}+6\overline{b}\right)$，则 $\begin{cases} 1=6\lambda \\ m=6\lambda \end{cases}$，解得 $m=1$。故选：B
    \end{description}
    \item 【答案】C
    \begin{description}
        \item【详解】设圆台的上底面半径为 $r$，下底面半径为 $R$，则利用弧长公式可得 $2\pi r=\frac{2\pi}{3}\times 12$，即 $r=4$；$2\pi R=\frac{2\pi}{3}\times 27$，即 $R=9$；又圆台的母线长为 $l=27-12=15$，所以圆台的侧面积 $S=\pi(4+9)\times 15=195\pi$，故选：C。
    \end{description}
    \item 【答案】D
    \begin{description}
        \item【详解】因为 $\frac{\overline{BA}\cdot\overline{AC}}{\overline{BC}}+\frac{\overline{AC}\cdot\overline{BC}}{\overline{BC}}=0$，所以 $\overline{BA}\cdot\overline{AC}+\overline{AC}\cdot\overline{BC}=0$，所以 $\overline{AC}\cdot\left(\overline{BA}+\overline{BC}\right)=0$，所以 $\left(\overline{BC}-\overline{BA}\right)\cdot\left(\overline{BA}+\overline{BC}\right)=0$，所以 $\overline{BC}^{2}=\overline{BA}^{2}$，即 $BC=BA$，又 $\frac{\overline{BC}}{\overline{BC}}\cdot\frac{\overline{AB}}{\overline{AB}}=1\times 1\times(-\cos B)=\frac{1}{2}$，所以 $\cos B=-\frac{1}{2}$，所以 $\angle B=\frac{2\pi}{3}$，所以 $\triangle ABC$ 为等腰非等边三角形。
    \end{description}
    \begin{description}
        \item故选：D
    \end{description}
    \item 【答案】C
    \begin{description}
        \item【详解】如图，作出圆锥 $SO$ 的轴截面 $SAB$，
    \end{description}
\end{enumerate}
